function renderTiposChart(weeks){if(!weeks.length)return;const allLabels=new Set();weeks.forEach(w=>{if(w.tipos)Object.keys(canonicalTipos(w.tipos)).forEach(l=>allLabels.add(l));});let fl=[...allLabels];if(tiposFilter==='sem_portaria')fl=fl.filter(l=>l!=='Portaria receb.');else if(tiposFilter==='estoque')fl=fl.filter(l=>TIPO_GROUPS[l]==='estoque');else if(tiposFilter==='operacional')fl=fl.filter(l=>TIPO_GROUPS[l]==='operacional'||TIPO_GROUPS[l]==='portaria');const lc=canonicalTipos(weeks[weeks.length-1].tipos||{});fl.sort((a,b)=>(lc[b]?.total||0)-(lc[a]?.total||0));const ds=fl.map(l=>({label:l,data:weeks.map(w=>{const ct=canonicalTipos(w.tipos||{});return ct[l]?.total||0;}),backgroundColor:TIPO_COLORS[l]||'#888',borderColor:TIPO_COLORS[l]||'#888',borderWidth:0,borderRadius:2}));document.getElementById('tiposLegend').innerHTML=fl.map(l=>`<span class="legend-item"><span class="legend-dot" style="background:${TIPO_COLORS[l]||'#888'}"></span>${l}</span>`).join('');if(tiposChart)tiposChart.destroy();tiposChart=new Chart(document.getElementById('tiposChart'),{type:'bar',data:{labels:weeks.map(w=>w.date.substring(0,5)),datasets:ds},options:{...go,plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>` ${ctx.dataset.label}: ${Math.round(ctx.parsed.y).toLocaleString('pt-BR')}`,footer:items=>'Total: '+Math.round(items.reduce((s,i)=>s+i.parsed.y,0)).toLocaleString('pt-BR')}}},scales:{x:{stacked:true,ticks:ts,grid:{display:false}},y:{stacked:true,ticks:{...ts,callback:v=>v>=1000?(v/1000).toFixed(0)+'k':v},grid:{color:gc}}}}});}
