function renderUnidades(w){if(!w.resumo){document.getElementById('tbodyUnidades').innerHTML='<tr><td colspan="7" style="text-align:center;color:#8a9ab8;padding:20px">Sem dados</td></tr>';return;}const rows=Object.entries(w.resumo).sort((a,b)=>b[1].total-a[1].total);const maxT=rows[0]?.[1]?.total||1,gTotal=rows.reduce((s,[,v])=>s+v.total,0);let html='';rows.forEach(([u,v])=>{const pct=v.total?v.d5p/v.total:0,d25=v.d2+v.d3+v.d4+v.d5;const badge=pct>=.8?'badge-red':pct>=.3?'badge-amber':'badge-green';html+=`<tr><td>${u}</td><td>${fmt(v.total)}</td><td style="color:#0E6B30;font-weight:600">${fmt(v.d1)}</td><td style="color:#A04700;font-weight:600">${fmt(d25)}</td><td style="color:#8B1A10;font-weight:600">${fmt(v.d5p)}</td><td><span class="badge ${badge}">${(pct*100).toFixed(0)}%</span></td><td style="min-width:90px"><div style="font-size:10px;color:#7a8da8">${(v.total/gTotal*100).toFixed(1)}%</div><div class="bar-bg"><div class="bar-fill" style="width:${(v.total/maxT*100).toFixed(0)}%"></div></div></td></tr>`;});const gd5p=rows.reduce((s,[,v])=>s+v.d5p,0),gd1=rows.reduce((s,[,v])=>s+v.d1,0),gd25=rows.reduce((s,[,v])=>s+v.d2+v.d3+v.d4+v.d5,0);html+=`<tr class="total-row"><td>Total geral</td><td>${fmt(gTotal)}</td><td>${fmt(gd1)}</td><td>${fmt(gd25)}</td><td>${fmt(gd5p)}</td><td><span class="badge badge-red">${(gd5p/gTotal*100).toFixed(0)}%</span></td><td>100%</td></tr>`;document.getElementById('tbodyUnidades').innerHTML=html;}
function renderTiposTable(w){if(!w.tipos){document.getElementById('tbodyTipos').innerHTML='<tr><td colspan="7" style="text-align:center;color:#8a9ab8;padding:20px">Sem dados</td></tr>';return;}const ct=canonicalTipos(w.tipos);const rows=Object.entries(ct).sort((a,b)=>b[1].total-a[1].total);const gTotal=rows.reduce((s,[,v])=>s+v.total,0);let html='';rows.forEach(([sg,v])=>{const pct=v.total?v.d5p/v.total:0,d25=v.d2+v.d3+v.d4+v.d5;html+=`<tr><td>${sg}</td><td>${fmt(v.total)}</td><td style="color:#0E6B30;font-weight:600">${fmt(v.d1)}</td><td style="color:#A04700;font-weight:600">${fmt(d25)}</td><td style="color:#8B1A10;font-weight:600">${fmt(v.d5p)}</td><td>${(pct*100).toFixed(0)}%</td><td>${(v.total/gTotal*100).toFixed(1)}%</td></tr>`;});const gd5p=rows.reduce((s,[,v])=>s+v.d5p,0),gd1=rows.reduce((s,[,v])=>s+v.d1,0),gd25=rows.reduce((s,[,v])=>s+v.d2+v.d3+v.d4+v.d5,0);html+=`<tr class="total-row"><td>Total geral</td><td>${fmt(gTotal)}</td><td>${fmt(gd1)}</td><td>${fmt(gd25)}</td><td>${fmt(gd5p)}</td><td>${(gd5p/gTotal*100).toFixed(0)}%</td><td>100%</td></tr>`;document.getElementById('tbodyTipos').innerHTML=html;}
function renderHistorico(weeks){let html='';weeks.forEach((w,i)=>{const prev=i>0?weeks[i-1]:null;const d=prev?w.total-prev.total:null;const dStr=d===null?'—':d>0?`<span class="delta-up">▲ +${Math.abs(d).toLocaleString('pt-BR')}</span>`:d<0?`<span class="delta-down">▼ ${d.toLocaleString('pt-BR')}</span>`:`<span class="delta-flat">— 0</span>`;const isCurr=i===weeks.length-1,isOld=w.date==='04/05/2026'||w.date==='15/05/2026';html+=`<tr ${isCurr?'style="font-weight:600"':''}><td>${w.date}${isCurr?' <span class="badge badge-blue">atual</span>':''}${isOld?' <span class="badge badge-amber">*</span>':''}</td><td>${fmt(w.total)}</td><td style="color:#8B1A10;font-weight:600">${fmt(w.d5p)}</td><td>${pctFmt(w.pct)}</td><td style="color:#0E6B30;font-weight:600">${fmt(w.d1)}</td><td>${dStr}</td><td>${sparkline(weeks.slice(Math.max(0,i-5),i+1).map(x=>x.total))}</td></tr>`;});document.getElementById('tbodyHistorico').innerHTML=html;}
function sparkline(values){if(values.length<2)return'';const min=Math.min(...values),max=Math.max(...values),range=max-min||1;const w=70,h=20,pts=values.map((v,i)=>`${(i/(values.length-1)*w).toFixed(1)},${((1-(v-min)/range)*(h-4)+2).toFixed(1)}`).join(' ');const last=values[values.length-1],prev2=values[values.length-2];return `<svg width="${w}" height="${h}" aria-hidden="true"><polyline points="${pts}" fill="none" stroke="${last>prev2?'#C0392B':last<prev2?'#1E8449':'#7a8da8'}" stroke-width="1.5" stroke-linejoin="round"/></svg>`;}
