// ── switchView ──────────────────────────────────────────────────────────────
function switchView(v) {
  document.getElementById('viewDashboard').style.display = v==='dashboard' ? 'block' : 'none';
  document.getElementById('panelDiagnostico').style.display = v==='diagnostico' ? 'block' : 'none';
  document.getElementById('navDash').style.color = v==='dashboard' ? '#0A2A5E' : '#4a5e7a';
  document.getElementById('navDash').style.borderBottomColor = v==='dashboard' ? '#0A2A5E' : 'transparent';
  document.getElementById('navDiag').style.color = v==='diagnostico' ? '#0A2A5E' : '#4a5e7a';
  document.getElementById('navDiag').style.borderBottomColor = v==='diagnostico' ? '#0A2A5E' : 'transparent';
  if (v === 'diagnostico') renderDiagnostico(weeksCache);
}

let bubbleChart = null;

function renderDiagnostico(weeks) {
  if (!weeks || !weeks.length) return;
  const curr = weeks[weeks.length - 1];
  const prev = weeks.length > 1 ? weeks[weeks.length - 2] : null;

  document.getElementById('diagWeekLabel').textContent = curr.date;

  if (!curr.resumo) return;

  // Build unit rows with zone classification
  function avgAgingUnit(v) {
    const d25 = v.d2 + v.d3 + v.d4 + v.d5;
    return v.total ? (v.d1*1 + d25*3.5 + v.d5p*7) / v.total : 0;
  }

  const units = Object.entries(curr.resumo).map(([u, v]) => {
    const pct = v.total ? v.d5p / v.total * 100 : 0;
    const prevV = prev?.resumo?.[u];
    const prevPct = prevV?.total ? prevV.d5p / prevV.total * 100 : null;
    const delta = prevPct !== null ? pct - prevPct : null;
    const avg = avgAgingUnit(v);
    // Zone based on aging, mesmos limites (2 e 5.5) das faixas sombreadas do
    // gráfico de bolhas — precisa bater com xBound1/xBound2 lá embaixo, senão
    // a bolha some numa faixa e o resumo conta ela em outra.
    const zone = avg > 5.5 ? 'critico' : avg > 2 ? 'atencao' : 'linha';
    // d5p delta
    const prevD5p = prevV?.d5p ?? null;
    const d5pDelta = prevD5p !== null ? v.d5p - prevD5p : null;
    return { u, ...v, pct, prevPct, delta, zone, avg, d5pDelta };
  }).sort((a, b) => b.avg - a.avg);

  // Zone summaries
  const critico   = units.filter(u => u.zone === 'critico');
  const atencao = units.filter(u => u.zone === 'atencao');
  const linha     = units.filter(u => u.zone === 'linha');

  document.getElementById('zoneCriticoCount').textContent  = critico.length;
  document.getElementById('zoneAtencaoCount').textContent = atencao.length;
  document.getElementById('zoneLinhaCount').textContent    = linha.length;
  document.getElementById('zoneCriticoList').textContent   = critico.map(u => u.u).join(' · ');
  document.getElementById('zoneAtencaoList').textContent = atencao.map(u => u.u).join(' · ');
  document.getElementById('zoneLinhaList').textContent     = linha.filter(u=>u.total>10).map(u => u.u).join(' · ');

  // Bubble chart
  const zoneColor = { critico: '#C0392B', atencao: '#E67E22', linha: '#1E8449' };
  const maxTotal = Math.max(...units.map(u => u.total), 1);

  // X = weighted aging position: 1D→x=1, 2-5D→x=3.5, >5D→x=7
  // Zone/cor vem de u.zone (calculado acima a partir dessa mesma posição)
  // R: sqrt scale proportional to total processes
  const labeledDatasets = units.filter(u => u.total > 0).map(u => {
    const v = curr.resumo[u.u] || u;
    const d25 = (v.d2||0)+(v.d3||0)+(v.d4||0)+(v.d5||0);
    const d1  = v.d1||0, d5p = v.d5p||0;
    // Reusa a mesma zona/posição já calculada pra essa unidade lá em cima —
    // antes a cor vinha do bucket com mais processos em número absoluto, que
    // podia discordar de onde a bolha cai no eixo X (média ponderada por
    // aging). Isso fazia bolha verde cair dentro da faixa laranja.
    const { zone, avg: wx } = u;
    // R: sqrt scale — 0..48 range
    const r = Math.max(7, Math.round(Math.sqrt(v.total / maxTotal) * 46) + 7);
    const color = zoneColor[zone];
    return {
      label: u.u,
      data: [{ x: +wx.toFixed(2), y: v.total, r }],
      backgroundColor: color + 'BB',
      borderColor: color,
      borderWidth: 2,
      total: v.total, d1, d25, d5p, zone,
    };
  });
  if (bubbleChart) bubbleChart.destroy();
  bubbleChart = new Chart(document.getElementById('bubbleChart'), {
    type: 'bubble',
    data: { datasets: labeledDatasets },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: {
          enabled: false,
          external: function(context) {
            let tip = document.getElementById('bubbleTip');
            if (!tip) {
              tip = document.createElement('div');
              tip.id = 'bubbleTip';
              tip.style.cssText = 'position:fixed;pointer-events:none;background:#0A2A5E;color:#fff;border-radius:8px;padding:10px 14px;font-size:12px;font-family:Montserrat,sans-serif;line-height:1.6;z-index:9999;box-shadow:0 4px 12px rgba(0,0,0,.25);max-width:200px;transition:opacity .1s';
              document.body.appendChild(tip);
            }
            if (context.tooltip.opacity === 0) { tip.style.opacity='0'; return; }
            const ds = context.tooltip.dataPoints?.[0]?.dataset;
            const pt = context.tooltip.dataPoints?.[0]?.raw;
            if (!ds || !pt) return;
            const zoneColor = ds.borderColor || '#fff';
            tip.innerHTML = '<div style="font-weight:700;font-size:13px;margin-bottom:6px;border-bottom:1px solid rgba(255,255,255,.3);padding-bottom:5px">'+ds.label+'</div>'
              + '<div style="color:rgba(255,255,255,.85)">Total: <strong style="color:#fff">'+((ds.total||0).toLocaleString('pt-BR'))+'</strong></div>'
              + '<div style="color:rgba(255,255,255,.85)">Hoje (1D): <strong style="color:#fff">'+((ds.d1||0).toLocaleString('pt-BR'))+'</strong></div>'
              + '<div style="color:rgba(255,255,255,.85)">2–5 dias: <strong style="color:#fff">'+((ds.d25||0).toLocaleString('pt-BR'))+'</strong></div>'
              + '<div style="color:rgba(255,255,255,.85)">&gt; 5 dias: <strong style="color:#fff">'+((ds.d5p||0).toLocaleString('pt-BR'))+'</strong></div>';
            // Position: follow mouse, stay inside viewport
            const e = context.chart.canvas.getBoundingClientRect();
            const mx = context.tooltip.caretX + e.left;
            const my = context.tooltip.caretY + e.top;
            const tw = 200, th = 100;
            const vw = window.innerWidth, vh = window.innerHeight;
            tip.style.left = (mx + 16 + tw > vw ? mx - tw - 16 : mx + 16) + 'px';
            tip.style.top  = (my + 16 + th > vh ? my - th - 16 : my + 16) + 'px';
            tip.style.opacity = '1';
          },
        },
      },
      scales: {
        x: {
          min: 0, max: 8,
          title: { display: true, text: '← Em linha (hoje)          Atenção (2–5d)          Crítico (>5d) →', color: '#2d3d56', font: { size: 11, weight: '700' } },
          ticks: {
            font: { size: 11 }, color: '#2d3d56', stepSize: 0.5,
            callback: v => {
              if (v === 1) return '1D';
              if (v === 3.5) return '2–5D';
              if (v === 7) return '>5D';
              return '';
            }
          },
          grid: { color: 'rgba(0,0,0,.04)' },
        },
        y: {
          type: 'logarithmic',
          min: 1,
          title: { display: true, text: 'Total de processos (escala log)', color: '#2d3d56', font: { size: 11, weight: '700' } },
          ticks: {
            font: { size: 11 }, color: '#2d3d56',
            callback: v => {
              if ([1,2,5,10,20,50,100,200,500,1000,2000,5000,10000].includes(v))
                return v >= 1000 ? (v/1000).toFixed(0)+'k' : v;
              return '';
            }
          },
          grid: { color: 'rgba(0,0,0,.04)' },
        }
      },
    },
    plugins: [{
      id: 'zoneBandsAndLabels',
      beforeDraw(chart) {
        const { ctx, chartArea: { left, right, top, bottom }, scales: { x } } = chart;
        const x40 = x.getPixelForValue(40), x80 = x.getPixelForValue(80);
        ctx.save();
        const xBound1 = x.getPixelForValue(2);   // 1D | 2-5D boundary
        const xBound2 = x.getPixelForValue(5.5); // 2-5D | >5D boundary
        ctx.fillStyle='rgba(30,132,73,.08)';  ctx.fillRect(left, top, Math.min(xBound1,right)-left, bottom-top);
        ctx.fillStyle='rgba(230,126,34,.08)'; ctx.fillRect(Math.max(xBound1,left), top, Math.min(xBound2,right)-Math.max(xBound1,left), bottom-top);
        ctx.fillStyle='rgba(192,57,43,.08)';  ctx.fillRect(Math.max(xBound2,left), top, right-Math.max(xBound2,left), bottom-top);
        ctx.setLineDash([5,4]); ctx.lineWidth=1.5;
        [[xBound1,'rgba(230,126,34,.6)'],[xBound2,'rgba(192,57,43,.6)']].forEach(([xp,c])=>{
          ctx.strokeStyle=c; ctx.beginPath(); ctx.moveTo(xp,top); ctx.lineTo(xp,bottom); ctx.stroke();
        });
        ctx.setLineDash([]);
        ctx.font='bold 11px Montserrat,sans-serif'; ctx.textAlign='center';
        [['🟢 EM LINHA (1D)',left,Math.min(xBound1,right),'rgba(14,107,48,.9)'],
         ['🟡 ATENÇÃO (2–5D)',Math.max(xBound1,left),Math.min(xBound2,right),'rgba(160,71,0,.95)'],
         ['🔴 CRÍTICO (>5D)',Math.max(xBound2,left),right,'rgba(139,26,16,.95)']].forEach(([lbl,x1,x2,c])=>{
          if(x2>x1+20){ctx.fillStyle=c; ctx.fillText(lbl,(x1+x2)/2,top+18);}
        });
        ctx.restore();
      },
      afterDraw(chart) {
        const { ctx, scales: { x, y }, chartArea } = chart;
        ctx.save();
        ctx.font='600 10.5px Montserrat,sans-serif'; ctx.textBaseline='middle';
        chart.data.datasets.forEach(ds => {
          if (!ds.data[0]) return;
          const pt=ds.data[0];
          const px=x.getPixelForValue(pt.x), r=pt.r||10;
          // Nunca deixa o rótulo da bolha subir em cima da linha do rótulo da
          // faixa (desenhada em beforeDraw, em top+18) — bolhas com total
          // próximo do máximo do eixo log ficam bem perto do topo.
          const py=Math.max(y.getPixelForValue(pt.y), chartArea.top+26);
          const label=ds.label||'';
          const short=label.length>16?label.substring(0,15)+'…':label;
          const tw=ctx.measureText(short).width;
          const goRight=px+r+6+tw < chartArea.right;
          ctx.textAlign=goRight?'left':'right';
          const lx=goRight?px+r+6:px-r-6;
          // White halo for legibility
          ctx.strokeStyle='rgba(255,255,255,.95)'; ctx.lineWidth=3;
          ctx.strokeText(short,lx,py);
          ctx.fillStyle=ds.borderColor||'#333';
          ctx.fillText(short,lx,py);
        });
        ctx.restore();
      }
    }]
  });



  // Detail table
  const diagColors = { critico: '#C0392B', atencao: '#E67E22', linha: '#1E8449' };
  const diagLabels = { critico: '🔴 Crítico', atencao: '🟡 Atenção', linha: '🟢 Em linha' };

  function diagAction(u) {
    // Proximity to zone boundaries
    const nearAtencao  = u.pct >= 32 && u.pct < 40;  // within 8pp of atencao boundary
    const nearCritico  = u.pct >= 68 && u.pct < 80;  // within 12pp of critico boundary
    const rising  = u.delta !== null && u.delta > 0;
    const falling = u.delta !== null && u.delta < -3;
    const fastRising = u.delta !== null && u.delta > 8;
    const fastFalling = u.delta !== null && u.delta < -8;

    if (u.zone === 'critico') {
      if (u.pct >= 99)     return '🚨 Volume quase 100% represado — investigar gargalo estrutural';
      if (fastRising)      return '⚠ Escalando rapidamente — ação imediata necessária';
      if (fastFalling)     return '📉 Reduzindo — manter esforço de liberação';
      return '🔴 Reduzir backlog >5D — priorizar processos mais antigos';
    }
    if (u.zone === 'atencao') {
      if (nearCritico && fastRising) return '⚠ Próximo do limite crítico (80%) e subindo — monitorar diariamente';
      if (fastRising)      return '⬆ Tendência de alta — risco de entrar em zona crítica';
      if (fastFalling)     return '⬇ Melhorando — manter ritmo de liberação';
      return '🟡 Zona de atenção — acompanhar evolução na próxima semana';
    }
    // Em linha
    if (u.total === 0)    return '—';
    if (u.pct === 0)      return '✅ Todos os processos recentes — operação saudável';
    if (nearAtencao && rising)  return '👀 Próximo do limiar de atenção (40%) e subindo — monitorar';
    if (nearAtencao)      return '⚠ Próximo do limiar de atenção (40%) — acompanhar';
    if (fastRising)       return '👀 Alta relevante — verificar se há represamento em formação';
    if (falling)          return '✅ Melhorando — dentro do esperado';
    return '✅ Dentro do esperado';
  }

  let html = '';
  units.forEach(u => {
    const color = diagColors[u.zone];
    // pct delta
    const dStr = u.delta === null ? '—' :
      u.delta > 0 ? `<span style="color:#8B1A10;font-weight:700">▲ +${u.delta.toFixed(1)}pp</span>` :
      u.delta < 0 ? `<span style="color:#0E6B30;font-weight:700">▼ ${u.delta.toFixed(1)}pp</span>` :
      '<span style="color:#7a8da8">→ 0pp</span>';
    // d5p delta (pre-computed in units array)
    const d5pDelta = u.d5pDelta !== undefined ? u.d5pDelta : null;
    const d5pStr = d5pDelta === null ? '' :
      d5pDelta > 0 ? ` <span style="color:#8B1A10;font-weight:700;font-size:10px">(▲+${d5pDelta.toLocaleString('pt-BR')})</span>` :
      d5pDelta < 0 ? ` <span style="color:#0E6B30;font-weight:700;font-size:10px">(▼${d5pDelta.toLocaleString('pt-BR')})</span>` : '';

    const trend4 = weeks.slice(-4).map(w => {
      const v = w.resumo?.[u.u];
      return v?.total ? v.d5p / v.total * 100 : null;
    });
    const trendStr = trend4.every(v => v === null) ? '—' : sparklinePct(trend4, u.pct >= 80 ? '#C0392B' : u.pct >= 40 ? '#E67E22' : '#1E8449');

    // Row highlight: red background if d5p increased vs previous week
    const rowBg = d5pDelta !== null && d5pDelta > 0 ? 'background:rgba(139,26,16,.04);' : '';
    const d5pColor = d5pDelta !== null && d5pDelta > 0 ? 'color:#8B1A10' : 'color:#8B1A10';
    html += `<tr style="${rowBg}">
      <td><span class="badge" style="background:${color}22;color:${color}">${diagLabels[u.zone]}</span></td>
      <td style="font-weight:700">${u.u}${d5pDelta !== null && d5pDelta > 0 ? ' <span style="color:#8B1A10;font-size:10px">●</span>' : ''}</td>
      <td>${fmt(u.total)}</td>
      <td style="color:#0E6B30;font-weight:600">${fmt(u.d1)}</td>
      <td style="${d5pColor};font-weight:700">${fmt(u.d5p)}${d5pStr}</td>
      <td><span style="font-weight:700;color:${color}">${u.pct.toFixed(1)}%</span></td>
      <td>${dStr}</td>
      <td>${trendStr}</td>
      <td style="font-size:11px;color:#2d3d56;max-width:220px">${diagAction(u)}</td>
    </tr>`;
  });
  document.getElementById('tbodyDiag').innerHTML = html;
}

function sparklinePct(values, _ignored) {
  const valid = values.filter(v => v !== null);
  if (valid.length < 2) return '—';
  const min = Math.min(...valid), max = Math.max(...valid), range = max - min || 1;
  const w = 70, h = 24;
  let pts = '', xi = 0;
  const vValid = [];
  values.forEach(v => { if (v !== null) vValid.push(v); });
  values.forEach(v => {
    if (v === null) return;
    const x = (xi / (vValid.length - 1) * w).toFixed(1);
    const y = ((1 - (v - min) / range) * (h - 6) + 3).toFixed(1);
    pts += `${x},${y} `;
    xi++;
  });
  // Color by direction: last vs first valid value
  const first = vValid[0], last = vValid[vValid.length - 1];
  const lineColor = last > first ? '#8B1A10' : last < first ? '#0E6B30' : '#7a8da8';
  const trend = last > first ? '▲' : last < first ? '▼' : '→';
  const trendColor = lineColor;
  return `<span style="display:inline-flex;align-items:center;gap:4px">
    <svg width="${w}" height="${h}" aria-hidden="true"><polyline points="${pts.trim()}" fill="none" stroke="${lineColor}" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/></svg>
    <span style="font-size:11px;font-weight:700;color:${trendColor}">${trend}</span>
  </span>`;
}


